const incoming = $input.first()?.json ?? {};
const body = incoming.body ?? incoming;

const courseName = body.course_name || body.courseName || "Unknown Course";
const courseId = body.course_id || body.courseId || "course_unknown";

const rawExamSets = [
  ...(Array.isArray(body.exam_sets) ? body.exam_sets : []),
  ...(Array.isArray(body.past_exams) ? body.past_exams : []),
  ...(Array.isArray(body.examSets) ? body.examSets : []),
  ...(Array.isArray(body.pastExams) ? body.pastExams : [])
];

const rawQuestions = [
  ...(Array.isArray(body.questions) ? body.questions : []),
  ...(Array.isArray(body.exam_questions) ? body.exam_questions : []),
  ...(Array.isArray(body.examQuestions) ? body.examQuestions : [])
];

let examItems = [];

if (rawQuestions.length > 0) {
  examItems = rawQuestions.map((question, index) => ({
    item_id: question.question_id || question.questionId || question.item_id || question.itemId || `q_${String(index + 1).padStart(3, "0")}`,
    source_id: question.source_id || question.sourceId || `exam_source_${String(index + 1).padStart(3, "0")}`,
    file_name: question.file_name || question.fileName || question.name || null,
    source_type: question.source_type || question.sourceType || "question",
    exam_year: question.exam_year || question.examYear || question.year || null,
    exam_name: question.exam_name || question.examName || question.title || null,
    question_type_hint: question.question_type || question.questionType || question.type || null,
    points: question.points || question.score || null,
    text: question.text || question.content || question.question || "",
    metadata: question.metadata || {}
  }));
} else {
  examItems = rawExamSets.map((exam, index) => ({
    item_id: exam.item_id || exam.itemId || exam.source_id || exam.sourceId || `exam_${String(index + 1).padStart(3, "0")}`,
    source_id: exam.source_id || exam.sourceId || `exam_${String(index + 1).padStart(3, "0")}`,
    file_name: exam.file_name || exam.fileName || exam.name || `exam_material_${index + 1}`,
    source_type: exam.source_type || exam.sourceType || "past_exam",
    exam_year: exam.exam_year || exam.examYear || exam.year || null,
    exam_name: exam.exam_name || exam.examName || exam.title || null,
    question_type_hint: exam.question_type || exam.questionType || null,
    points: exam.points || exam.score || null,
    text: exam.text || exam.content || "",
    metadata: exam.metadata || {}
  }));
}

const sourceTypes = [...new Set(examItems.map(item => item.source_type).filter(Boolean))];
const fileNames = [...new Set(examItems.map(item => item.file_name).filter(Boolean))];
const examYears = [...new Set(examItems.map(item => item.exam_year).filter(year => year !== null && year !== undefined))];

return [{
  json: {
    workflow_name: "exam_pattern_agent",
    course_id: courseId,
    course_name: courseName,
    exam_summary: {
      total_sources: examItems.length,
      source_types: sourceTypes,
      file_names: fileNames,
      exam_years: examYears
    },
    exam_items: examItems,
    constraints: {
      no_exam_prediction: true,
      no_must_test_claims: true,
      no_review_plan: true,
      evidence_required_for_each_pattern: true
    }
  }
}];

const llmResult = $input.first().json;

function pickRawOutput(value) {
  if (typeof value === "string") return value;
  if (value?.output !== undefined) return value.output;
  if (value?.response?.text !== undefined) return value.response.text;
  if (value?.generations?.[0]?.[0]?.text !== undefined) return value.generations[0][0].text;
  if (value?.choices?.[0]?.message?.content !== undefined) return value.choices[0].message.content;
  if (value?.text !== undefined) return value.text;
  if (value?.response !== undefined) return value.response;
  if (value?.message?.content !== undefined) return value.message.content;
  return value;
}

function stripCodeFence(text) {
  return text
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();
}

function parseJsonLoose(raw) {
  if (raw && typeof raw === "object") {
    if (raw.workflow_name || raw.question_analysis || raw.pattern_summary) return raw;
    raw = JSON.stringify(raw);
  }

  let text = String(raw ?? "").trim();
  text = stripCodeFence(text);

  try {
    return JSON.parse(text);
  } catch (firstError) {
    const start = text.indexOf("{");
    const end = text.lastIndexOf("}");
    if (start >= 0 && end > start) {
      const candidate = text.slice(start, end + 1);
      return JSON.parse(candidate);
    }
    throw firstError;
  }
}

let parsed;
try {
  parsed = parseJsonLoose(pickRawOutput(llmResult));
} catch (error) {
  return [{
    json: {
      workflow_name: "exam_pattern_agent",
      parser_error: true,
      error_message: error.message,
      raw_llm_output: llmResult
    }
  }];
}

parsed.workflow_name = parsed.workflow_name || "exam_pattern_agent";
parsed.exam_summary = parsed.exam_summary || {};
parsed.question_analysis = Array.isArray(parsed.question_analysis) ? parsed.question_analysis : [];
parsed.pattern_summary = Array.isArray(parsed.pattern_summary) ? parsed.pattern_summary : [];
parsed.question_type_distribution = parsed.question_type_distribution || {};
parsed.ability_distribution = parsed.ability_distribution || {};
parsed.uncertainties = Array.isArray(parsed.uncertainties) ? parsed.uncertainties : [];
parsed._agent_meta = {
  parsed_at: new Date().toISOString(),
  node: "Parse OpenAI JSON"
};

return [{ json: parsed }];
